import { setup, assign } from 'xstate';

type Ctx = { peerId: string; retries: number; reason?: string };
type Ev =
  | { type: 'CALL'; peerId: string }
  | { type: 'ACCEPT' }
  | { type: 'CONNECTED' }
  | { type: 'DISCONNECT' }
  | { type: 'RECONNECTED' }
  | { type: 'HANG_UP' }
  | { type: 'FAIL'; reason: string };

export const callMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canRetry: ({ context }) => context.retries < 3
  }
}).createMachine({
  id: 'call',
  initial: 'idle',
  context: { peerId: '', retries: 0 },
  states: {
    idle: {
      on: { CALL: { target: 'ringing', actions: assign({ peerId: ({ event }) => event.peerId, retries: () => 0 }) } }
    },
    ringing: {
      on: {
        ACCEPT: 'connecting',
        HANG_UP: 'ended'
      }
    },
    connecting: {
      on: {
        CONNECTED: 'inCall',
        FAIL: { target: 'ended', actions: assign({ reason: ({ event }) => event.reason }) }
      }
    },
    inCall: {
      on: {
        DISCONNECT: 'reconnecting',
        HANG_UP: 'ended'
      }
    },
    reconnecting: {
      entry: assign({ retries: ({ context }) => context.retries + 1 }),
      on: {
        RECONNECTED: 'inCall',
        FAIL: [
          { target: 'connecting', guard: 'canRetry' },
          { target: 'ended', actions: assign({ reason: () => 'max retries' }) }
        ],
        HANG_UP: 'ended'
      }
    },
    ended: { type: 'final' }
  }
});
