  id: 'outgoing',
  initial: 'idle',
  context: { peer: '', timedOut: false },
  states: {
    idle: {
      on: { DIAL: { target: 'ringing', actions: ['setPeer', 'clearTimeout'] } }
    },
    ringing: {
      after: {
        ringTimeout: { target: 'ended', actions: 'markTimeout' }
      },
      on: {
        ANSWER: 'inCall',
        CANCEL: 'ended'
      }
    },
    inCall: { on: { CANCEL: 'ended' } },
    ended: { type: 'final' }
  }
