import { setup, assign, fromPromise } from 'xstate';

type Item = { readonly id: string; readonly title: string };
type Ctx = { items: readonly Item[]; page: number; done: boolean; error?: string };
type Ev = { type: 'LOAD_MORE' } | { type: 'RETRY' };

declare const api: { page: (p: number) => Promise<{ items: readonly Item[]; hasMore: boolean }> };

export const feed = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    loadPage: fromPromise<{ items: readonly Item[]; hasMore: boolean }, { page: number }>(
      ({ input }) => api.page(input.page)
    )
  },
  guards: {
    notDone: ({ context }) => !context.done
  }
}).createMachine({
  id: 'feed',
  initial: 'idle',
  context: { items: [], page: 0, done: false },
  states: {
    idle: {
      on: { LOAD_MORE: { target: 'loading', guard: 'notDone' } }
    },
    loading: {
      invoke: {
        src: 'loadPage',
        input: ({ context }) => ({ page: context.page + 1 }),
        onDone: {
          target: 'idle',
          actions: assign({
            items: ({ context, event }) => [...context.items, ...event.output.items],
            page: ({ context }) => context.page + 1,
            done: ({ event }) => !event.output.hasMore
          })
        },
        onError: {
          target: 'error',
          actions: assign({ error: ({ event }) => String(event.error) })
        }
      }
    },
    error: {
      on: { RETRY: 'loading' }
    }
  }
});
