import { setup, assign, fromCallback } from 'xstate';

type Ctx = { page: number };
type Ev = { type: 'NEAR_BOTTOM' } | { type: 'LOADED' };

type ScrollIn = { threshold: number };
type ScrollOut = { type: 'NEAR_BOTTOM' };

const scrollSource = fromCallback<ScrollOut, ScrollIn>(({ sendBack, input }) => {
  const onScroll = () => {
    const remaining = document.body.scrollHeight - (window.scrollY + window.innerHeight);
    if (remaining < input.threshold) {
      sendBack({ type: 'NEAR_BOTTOM' });
    }
  };
  window.addEventListener('scroll', onScroll, { passive: true });
  return () => window.removeEventListener('scroll', onScroll);
});

export const scrollFeed = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { scrollSource }
}).createMachine({
  id: 'scrollFeed',
  initial: 'idle',
  context: { page: 0 },
  invoke: {
    src: 'scrollSource',
    input: { threshold: 200 }
  },
  states: {
    idle: { on: { NEAR_BOTTOM: 'loading' } },
    loading: {
      on: {
        LOADED: {
          target: 'idle',
          actions: assign({ page: ({ context }) => context.page + 1 })
        }
      }
    }
  }
});
```

