`fromCallback` turns an imperative event source (DOM listeners, WebSocket messages, timers) into an actor whose outbound events arrive via `sendBack`. The cleanup function returned by the callback runs automatically when the parent state exits, so there are no leaked listeners.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'RESIZE'; width: number } | { type: 'STOP' };
type ResizeOut = { type: 'RESIZE'; width: number };

const resizeSource = fromCallback<ResizeOut, void>(({ sendBack }) => {
  const onResize = () => sendBack({ type: 'RESIZE', width: window.innerWidth });
  window.addEventListener('resize', onResize);
  return () => window.removeEventListener('resize', onResize);
});

export const virtualList = setup({
  types: { events: {} as Ev },
  actors: { resizeSource }
}).createMachine({
  id: 'virtualList',
  initial: 'watching',
  states: {
    watching: {
      invoke: { src: 'resizeSource' },
      on: {
        RESIZE: 'watching',
        STOP: 'done'
      }
    },
    done: { type: 'final' }
  }
});
```

