import { setup, assign } from 'xstate';

type Ctx = { value: string; history: readonly string[]; future: readonly string[] };
type Ev = { type: 'SET'; value: string } | { type: 'UNDO' } | { type: 'REDO' };

export const undoable = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasHistory: ({ context }) => context.history.length > 0,
    hasFuture: ({ context }) => context.future.length > 0
  }
}).createMachine({
  id: 'undoable',
  initial: 'idle',
  context: { value: '', history: [], future: [] },
  states: {
    idle: {
      on: {
        SET: {
          actions: assign({
            history: ({ context }) => [...context.history, context.value],
            value: ({ event }) => event.value,
            future: () => [] as readonly string[]
          })
        },
        UNDO: {
          guard: 'hasHistory',
          actions: assign({
            value: ({ context }) => context.history[context.history.length - 1] ?? context.value,
            history: ({ context }) => context.history.slice(0, -1),
            future: ({ context }) => [context.value, ...context.future]
          })
        },
        REDO: {
          guard: 'hasFuture',
          actions: assign({
            value: ({ context }) => context.future[0] ?? context.value,
            history: ({ context }) => [...context.history, context.value],
            future: ({ context }) => context.future.slice(1)
          })
        }
      }
    }
  }
});
